if (e.data?.type === 'TEXT_SELECT' || e.data?.type === 'SENTENCE_SELECTED') {
    const { text, rect } = e.data;
    const currentScale = scaleRef.current || 1;

    // Viewport metrics
    const vp = document.getElementById('viewport');
    const scrollLeft = vp ? vp.scrollLeft : 0;
    const scrollTop = vp ? vp.scrollTop : 0;
    const vpW = vp ? vp.clientWidth : window.innerWidth;
    const vpH = vp ? vp.clientHeight : window.innerHeight;

    // 1. Calculate X (Center)
    // Clamp X so the 260px menu (130px half-width) stays within visible viewport
    // We add/subtract 140px (130 + padding) converted to book scale
    const minX = (scrollLeft + 140) / currentScale;
    const maxX = (scrollLeft + vpW - 140) / currentScale;

    let targetX = rect.x + (rect.width / 2);
    targetX = Math.max(minX, Math.min(maxX, targetX));

    // 2. Calculate Y (Top or Bottom)
    // Check space below visual selection bottom
    const visualBottom = (rect.y + rect.height) * currentScale - scrollTop;
    const spaceBelow = vpH - visualBottom;
    const visualTop = (rect.y * currentScale) - scrollTop;

    // Logic: Prefer Below. If spaceBelow < 200px AND spaceAbove > 200px, flip to above
    let placeBelow = true;
    if (spaceBelow < 200 && visualTop > 200) {
        placeBelow = false;
    }

    setContextMenu({
        x: targetX,
        y: placeBelow ? rect.y + rect.height : rect.y,
        placeBelow: placeBelow,
        text: text
    });
}

